-- Join from agent_runs to its tool calls
CREATE INDEX ON tool_call_logs (run_id);

-- Aggregate by tool name across all runs
CREATE INDEX ON tool_call_logs (tool_name, started_at DESC);

-- Filter by outcome — partial index covers only failures
CREATE INDEX ON tool_call_logs (status)
    WHERE status IN ('error', 'timeout');

-- Search tool inputs: WHERE input @> '{"url": "https://example.com"}'
CREATE INDEX ON tool_call_logs USING GIN (input);

-- Search tool results: WHERE result @> '{"status": "created"}'
CREATE INDEX ON tool_call_logs USING GIN (result);

-- Artifacts
CREATE INDEX ON tool_artifacts (log_id);
CREATE INDEX ON tool_artifacts (artifact_type, created_at DESC);

import anthropic

client = anthropic.Anthropic()

def run_agent_turn(conn, run_id: int, turn: int, messages: list) -> list:
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=4096,
        tools=[...],
        messages=messages,
    )

    tool_results = []
    for block in response.content:
        if block.type == "tool_use":
            try:
                result = execute_tool_call(conn, run_id, turn, block)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result),
                })
            except Exception as exc:
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"Error: {exc}",
                    "is_error": True,
                })
    return tool_results

MAX_INLINE_BYTES = 65_536  # 64 KB

def store_result(conn, log_id: int, result: dict) -> None:
    result_json = json.dumps(result)
    if len(result_json.encode()) <= MAX_INLINE_BYTES:
        with conn, conn.cursor() as cur:
            cur.execute(
                "UPDATE tool_call_logs SET result=%s, status='success' WHERE id=%s",
                (Json(result), log_id),
            )
    else:
        summary = {"truncated": True, "size_bytes": len(result_json), "keys": list(result.keys())}
        with conn, conn.cursor() as cur:
            cur.execute(
                "UPDATE tool_call_logs SET result=%s, status='success' WHERE id=%s",
                (Json(summary), log_id),
            )
            cur.execute(
                """
                INSERT INTO tool_artifacts (log_id, artifact_type, content, size_bytes)
                VALUES (%s, 'full_result', %s, %s)
                """,
                (log_id, Json(result), len(result_json)),
            )
